from typing import List
import heapq

"""
LeetCode 973. K Closest Points to Origin
Given an array of points where points[i] = [xi, yi] represents a point on the X-Y plane and an integer k, return the k closest points to the origin (0, 0).
The distance between two points on the X-Y plane is the Euclidean distance (i.e., √(x1 - x2)2 + (y1 - y2)2).
You may return the answer in any order. The answer is guaranteed to be unique (except for the order that it is in).
"""

"""
Approach 1: Min-heap of "size n" approach (store all n):
Push all n points into heap: O(n log n) (or O(n) build + pops).
Pop k: O(k log n).
Overall: O(n log n)

Approach 2: Max-heap of "size k" approach:
First k inserts: O(k log k).
For each remaining point (n-k), compare with heap top (O(1)):
    only if closer, replace root: O(log k).
Overall: O(n log k)
"""
from typing import List
import heapq

class Solution:
    def kClosest_MinHeap(self, points: List[List[int]], k: int) -> List[List[int]]:
        if k > len(points):
            return []
        if k == len(points):
            return points

        minHeap = []

        for point in points:
            x, y = point[0], point[1]
            dist = x * x + y * y
            heapq.heappush(minHeap, (dist, point))
            # heapq.heapify(minHeap)    # Heap always maintains it's property upon new element push - so don't need heapify() to slow down

        # Heap has N elements, get the first K minimum distance in results
        res = []
        for dist, point in minHeap:
            res.append(point)
        return res
    
    def kClosest_MaxHeap(self, points: List[List[int]], k:int) -> List[List[int]]:
        if k <= 0 or k > len(points):
            return []
        if k == len(points):
            return points

        maxHeap = []        # By Default, heapq() provides minHeap, to treat as maxHeap - negate value to be sorted i.e -dist
        for point in points:
            x, y = point[0], point[1]
            dist = x * x + y * y
            # Optimize: Limit Heap Size to K - no need for rest of the elements!
            if len(maxHeap) < k:
                heapq.heappush(maxHeap, (-dist, point))
            else:
                heapq.heappushpop(maxHeap, (-dist, point))

        
        # Now Heap has K highest dist points, just organize in results output
        res = []
        for dist, point in maxHeap:
            res.append(point)
        return res


